/// - [`KreuzbergError::Validation`] if `query` is empty or blank.
/// - [`KreuzbergError::MissingDependency`] if ONNX Runtime is not installed (ONNX path).
/// - [`KreuzbergError::Reranking`] if the preset is unknown or model download fails.
///
/// Since v5.0.0.
public func rerank(query: String, documents: [String], config: RerankerConfig) throws -> [RerankedDocument] {
        let _rb_query = RustString(query)
        let _rb_documents: RustVec<RustString> = { let v = RustVec<RustString>(); for s in documents { v.push(value: RustString(s)) }; return v }()
    return try RustBridge.rerank(_rb_query, _rb_documents, config).map { ref in var item = try RustBridge.RerankedDocument(ptr: ref.ptr); item.isOwned = false; return item }
}
/// Stub for builds without the `reranker` feature.
///
/// Since v5.0.0.
public func rerankAsync(query: String, documents: [String], config: RerankerConfig) async throws -> [RerankedDocument] {
    return try await Task.detached(priority: .userInitiated) {
        let _rb_query = RustString(query)
        let _rb_documents: RustVec<RustString> = { let v = RustVec<RustString>(); for s in documents { v.push(value: RustString(s)) }; return v }()
        let result = try RustBridge.rerankAsync(_rb_query, _rb_documents, config)
        var items: [RerankedDocument] = []
        for ref in result {
            var item = try RustBridge.RerankedDocument(ptr: ref.ptr)
            item.isOwned = false
            items.append(item)
        }
        return items
    }.value
}

